#### Arquivo 3: `src/utils.tsx`
*(Crie este arquivo dentro de src. Ele contém TODA a lógica, dados e serviços)*

```tsx
import React, { createContext, useState, useContext, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";

// --- TYPES ---
export type Gender = 'MALE' | 'FEMALE';
export type UserRole = 'USER' | 'ADMIN';

export interface User {
  id: string;
  name: string;
  gender: Gender;
  city: string;
  avatarUrl?: string;
  role: UserRole;
}

export interface Sponsor {
  id: string;
  name: string;
  imageUrl?: string;
  websiteUrl?: string;
  description: string;
}

export interface SupportResource {
  id: string;
  title: string;
  description: string;
  contact: string;
  type: 'PROFESSIONAL' | 'EMERGENCY' | 'GROUP';
  icon: string;
}

export interface ForumPost {
  id: string;
  author: string;
  content: string;
  likes: number;
  timestamp: string;
  topic: string;
  replies: any[];
  userHasLiked?: boolean;
}

// --- CONSTANTS ---
export const APP_NAME = "VARÃO10";
export const SUPPORT_EMAIL = "redesocialdoalfredo@gmail.com";
export const MOCK_VERIFIED_PROFILES = [
  { id: '1', name: 'Amanda Oliveira', age: 26, city: 'São Paulo, SP', imageUrl: 'https://picsum.photos/400/400?random=1', verified: true, bio: 'Advogada.', badges: ['Identidade Confirmada', 'Nada Consta'] },
  { id: '2', name: 'Juliana Costa', age: 29, city: 'Rio, RJ', imageUrl: 'https://picsum.photos/400/400?random=2', verified: true, bio: 'Empresária.', badges: ['Identidade Confirmada'] },
];

export const INITIAL_SPONSORS: Sponsor[] = [];
export const INITIAL_RESOURCES: SupportResource[] = [
    { id: '1', title: 'CVV - Valorização da Vida', description: 'Apoio emocional 24h.', contact: '188', type: 'EMERGENCY', icon: 'Phone' },
    { id: '2', title: 'Dr. Roberto Mendes', description: 'Psicólogo especializado.', contact: '11 99999-9999', type: 'PROFESSIONAL', icon: 'User' }
];

export const MOCK_FORUM_POSTS: ForumPost[] = [
    { id: '1', author: 'Guerreiro_SP', content: 'Cuidado com perfis que pedem PIX logo de cara.', likes: 42, timestamp: '2h atrás', topic: 'Alerta', replies: [] },
    { id: '2', author: 'Carlos M.', content: 'Foquem no trabalho e na saúde, varões.', likes: 128, timestamp: '1d atrás', topic: 'Geral', replies: [] }
];

// --- SERVICES ---
const ai = new GoogleGenAI({ apiKey: import.meta.env.VITE_API_KEY || '' });

export const analyzeProfileRisk = async (params: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Analise riscos para perfil: ${params.fullName}, ${params.city}. Contexto: App de segurança para homens. Seja breve e direto.`,
    });
    return response.text;
  } catch (e) { return "Simulação: Perfil com baixo risco aparente, mas mantenha cautela."; }
};

export const getSupportiveAdvice = async (msg: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: `Aja como um mentor estoico para homens. O usuário disse: "${msg}". Dê um conselho curto e forte.`,
    });
    return response.text;
  } catch (e) { return "Mantenha a cabeça erguida. Foque no que você controla."; }
};

// --- CONTEXTS ---
const AuthContext = createContext<any>(undefined);
export const AuthProvider: React.FC<{children: React.ReactNode}> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  useEffect(() => {
    const stored = localStorage.getItem('varao10_user');
    if (stored) setUser(JSON.parse(stored));
  }, []);
  const login = (u: User) => { setUser(u); localStorage.setItem('varao10_user', JSON.stringify(u)); };
  const logout = () => { setUser(null); localStorage.removeItem('varao10_user'); };
  return <AuthContext.Provider value={{ user, login, logout, isAuthenticated: !!user, isMale: user?.gender === 'MALE', isAdmin: user?.role === 'ADMIN' }}>{children}</AuthContext.Provider>;
};
export const useAuth = () => useContext(AuthContext);

const DataContext = createContext<any>(undefined);
export const DataProvider: React.FC<{children: React.ReactNode}> = ({ children }) => {
  const [sponsors, setSponsors] = useState<Sponsor[]>(INITIAL_SPONSORS);
  const [supportResources, setResources] = useState<SupportResource[]>(INITIAL_RESOURCES);
  const addSponsor = (s: Sponsor) => setSponsors([...sponsors, s]);
  const removeSponsor = (id: string) => setSponsors(sponsors.filter(x => x.id !== id));
  const addResource = (r: SupportResource) => setResources([...supportResources, r]);
  const removeResource = (id: string) => setResources(supportResources.filter(x => x.id !== id));
  return <DataContext.Provider value={{ sponsors, addSponsor, removeSponsor, supportResources, addResource, removeResource }}>{children}</DataContext.Provider>;
};
export const useData = () => useContext(DataContext);
```

#### Arquivo 4: `src/App.tsx`
*(Crie este arquivo dentro de src. Ele contém TODAS as telas do aplicativo)*

```tsx
import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useNavigate, useLocation, Navigate } from 'react-router-dom';
import { Shield, Search, CheckCircle, Menu, X, Lock, MessageSquare, HeartHandshake, Users, LogIn, LogOut, User, Send, ThumbsUp, Phone, Briefcase, Trash, Plus, Star } from 'lucide-react';
import { AuthProvider, DataProvider, useAuth, useData, analyzeProfileRisk, getSupportiveAdvice, MOCK_VERIFIED_PROFILES, MOCK_FORUM_POSTS, APP_NAME, SUPPORT_EMAIL } from './utils';

// --- COMPONENTS & PAGES ---

const ProtectedRoute = ({ children }: { children: React.ReactNode }) => {
  const { isAuthenticated } = useAuth();
  const location = useLocation();
  if (!isAuthenticated) return <Navigate to="/login" state={{ from: location }} replace />;
  return <>{children}</>;
};

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [menuOpen, setMenuOpen] = useState(false);
  const { user, logout, isAuthenticated, isMale, isAdmin } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => { logout(); navigate('/login'); setMenuOpen(false); };

  return (
    <div className="min-h-screen bg-[#050505] text-white font-sans flex flex-col">
      <header className="sticky top-0 z-50 bg-[#0A0A0A]/95 border-b border-white/10 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <Link to="/" className="flex items-center gap-2 font-serif text-2xl font-bold">
            <Shield className="text-[#D4AF37]" /> VARÃO<span className="text-[#D4AF37]">10</span>
          </Link>
          {/* Desktop Nav */}
          <nav className="hidden lg:flex items-center gap-6 text-sm font-medium uppercase tracking-wide text-gray-400">
             {isAuthenticated && (
               <>
                 <Link to="/consult" className="hover:text-[#D4AF37]">Consultar</Link>
                 <Link to="/verified" className="hover:text-[#D4AF37]">Verificadas</Link>
                 {(isMale || isAdmin) && (
                   <>
                     <Link to="/desabafo" className="hover:text-[#D4AF37]">Fórum</Link>
                     <Link to="/community" className="hover:text-[#D4AF37]">Comunidade</Link>
                     <Link to="/are-you-okay" className="hover:text-[#D4AF37]">Apoio</Link>
                   </>
                 )}
                 {isAdmin && <Link to="/admin" className="text-[#D4AF37] border border-[#D4AF37] px-2 py-1 rounded">ADMIN</Link>}
               </>
             )}
             {isAuthenticated ? (
               <button onClick={handleLogout} className="flex items-center gap-2 text-white ml-4"><LogOut size={16}/> Sair</button>
             ) : (
               <Link to="/login" className="bg-[#D4AF37] text-black px-4 py-2 font-bold rounded-sm">Entrar</Link>
             )}
          </nav>
          {/* Mobile Menu Toggle */}
          <button onClick={() => setMenuOpen(!menuOpen)} className="lg:hidden text-[#D4AF37]"><Menu /></button>
        </div>
      </header>
      {/* Mobile Menu */}
      {menuOpen && (
        <div className="lg:hidden bg-[#121212] p-4 border-b border-white/10 flex flex-col gap-4">
           {isAuthenticated && (
             <>
               <Link to="/consult" onClick={() => setMenuOpen(false)}>Consultar</Link>
               <Link to="/verified" onClick={() => setMenuOpen(false)}>Verificadas</Link>
               {(isMale || isAdmin) && <Link to="/desabafo" onClick={() => setMenuOpen(false)}>Fórum</Link>}
               {(isMale || isAdmin) && <Link to="/are-you-okay" onClick={() => setMenuOpen(false)}>Apoio</Link>}
               {isAdmin && <Link to="/admin" onClick={() => setMenuOpen(false)} className="text-[#D4AF37]">Painel ADMIN</Link>}
               <button onClick={handleLogout} className="text-left text-red-400">Sair</button>
             </>
           )}
           {!isAuthenticated && <Link to="/login" onClick={() => setMenuOpen(false)} className="text-[#D4AF37]">Entrar / Cadastrar</Link>}
        </div>
      )}
      <main className="flex-grow">{children}</main>
      <footer className="bg-[#0A0A0A] border-t border-white/10 py-8 text-center text-gray-500 text-sm">
        <p className="mb-2">© 2025 {APP_NAME}. Integridade e Segurança.</p>
        <p className="mb-4">{SUPPORT_EMAIL}</p>
        <a href="https://wa.me/5531992561343" target="_blank" className="inline-block animate-pulse text-white border border-white/20 px-3 py-1 rounded uppercase text-xs font-bold hover:bg-white hover:text-black">Patrocínio (WhatsApp)</a>
      </footer>
    </div>
  );
};

// --- PAGES ---

const Home = () => (
  <div className="py-20 px-4 text-center">
    <h1 className="text-5xl font-serif font-bold text-white mb-6">Proteja seu <span className="text-[#D4AF37]">Legado</span>.</h1>
    <p className="text-xl text-gray-400 mb-10 max-w-2xl mx-auto">Plataforma de inteligência e verificação de perfis. Valide antes de se comprometer.</p>
    <div className="flex justify-center gap-4">
      <Link to="/consult" className="px-8 py-4 bg-[#D4AF37] text-black font-bold uppercase rounded-sm flex items-center gap-2"><Search size={20}/> Consultar</Link>
      <Link to="/verified" className="px-8 py-4 border border-white/20 text-white font-bold uppercase rounded-sm">Ver Verificadas</Link>
    </div>
  </div>
);

const Login = () => {
  const { login, isAuthenticated } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  // @ts-ignore
  const from = location.state?.from?.pathname || '/';
  const [mode, setMode] = useState<'SELECT' | 'FORM'>('SELECT');
  const [role, setRole] = useState<'MALE' | 'FEMALE'>('MALE');
  const [name, setName] = useState('');
  const [city, setCity] = useState('');
  const [adminPass, setAdminPass] = useState('');

  useEffect(() => { if (isAuthenticated) navigate(from, { replace: true }); }, [isAuthenticated]);

  const handleLogin = (isAdmin = false) => {
    if (isAdmin && adminPass !== 'Amesmacom*2025') return alert('Senha incorreta');
    login({ 
      id: Date.now().toString(), 
      name: isAdmin ? 'Admin' : name, 
      gender: role, 
      city: isAdmin ? 'Base' : city, 
      role: isAdmin ? 'ADMIN' : 'USER',
      avatarUrl: isAdmin ? 'https://ui-avatars.com/api/?name=Admin' : undefined
    });
    navigate(isAdmin ? '/admin' : from, { replace: true });
  };

  if (mode === 'SELECT') return (
    <div className="max-w-4xl mx-auto py-20 px-4 text-center">
      <h2 className="text-3xl font-bold mb-8">Bem-vindo ao Varão10</h2>
      <div className="grid md:grid-cols-2 gap-6 mb-8">
        <button onClick={() => {setRole('MALE'); setMode('FORM')}} className="p-10 bg-[#121212] border border-[#D4AF37]/30 hover:border-[#D4AF37] rounded-sm group">
          <Shield className="mx-auto mb-4 text-[#D4AF37] group-hover:scale-110 transition" size={40} />
          <h3 className="text-2xl font-bold text-white">Sou Homem</h3>
          <p className="text-gray-500 text-sm mt-2">Acesso à comunidade e consultas.</p>
        </button>
        <button onClick={() => {setRole('FEMALE'); setMode('FORM')}} className="p-10 bg-[#121212] border border-rose-500/30 hover:border-rose-400 rounded-sm group">
          <Star className="mx-auto mb-4 text-rose-400 group-hover:scale-110 transition" size={40} />
          <h3 className="text-2xl font-bold text-white">Sou Mulher</h3>
          <p className="text-gray-500 text-sm mt-2">Criar perfil e solicitar verificação.</p>
        </button>
      </div>
      <div className="mt-8 border-t border-white/10 pt-8">
        <input type="password" placeholder="Senha Admin" className="bg-black/50 border border-white/10 p-2 rounded text-white mr-2" value={adminPass} onChange={e => setAdminPass(e.target.value)} />
        <button onClick={() => handleLogin(true)} className="text-xs uppercase font-bold text-gray-500 hover:text-[#D4AF37]">Acesso ADM</button>
      </div>
    </div>
  );

  return (
    <div className="max-w-md mx-auto py-20 px-4">
      <button onClick={() => setMode('SELECT')} className="text-sm text-gray-500 mb-4">&larr; Voltar</button>
      <div className="bg-[#121212] p-8 border border-white/10 rounded-sm">
        <h2 className="text-2xl font-bold mb-6">Cadastro {role === 'MALE' ? 'Masculino' : 'Feminino'}</h2>
        <input className="w-full bg-black/50 border border-white/20 p-3 mb-4 text-white rounded" placeholder="Seu Nome" value={name} onChange={e => setName(e.target.value)} />
        <input className="w-full bg-black/50 border border-white/20 p-3 mb-6 text-white rounded" placeholder="Sua Cidade" value={city} onChange={e => setCity(e.target.value)} />
        <button onClick={() => handleLogin(false)} className="w-full bg-[#D4AF37] py-3 font-bold uppercase rounded text-black">Entrar</button>
      </div>
    </div>
  );
};

const ConsultProfile = () => {
  const navigate = useNavigate();
  const [data, setData] = useState({ fullName: '', city: '' });
  return (
    <div className="max-w-2xl mx-auto py-20 px-4">
      <h2 className="text-3xl font-serif font-bold mb-6">Consultar Perfil</h2>
      <div className="bg-[#121212] p-8 border border-white/10 rounded-sm">
        <label className="block text-[#D4AF37] text-xs font-bold uppercase mb-2">Nome Completo</label>
        <input className="w-full bg-black/50 border border-white/20 p-3 mb-4 text-white" value={data.fullName} onChange={e => setData({...data, fullName: e.target.value})} />
        <label className="block text-gray-500 text-xs font-bold uppercase mb-2">Cidade</label>
        <input className="w-full bg-black/50 border border-white/20 p-3 mb-6 text-white" value={data.city} onChange={e => setData({...data, city: e.target.value})} />
        <p className="text-xs text-gray-500 mb-6 text-justify">O Varão10 consulta apenas fontes públicas (OSINT).</p>
        <button onClick={() => navigate('/results', { state: { searchParams: data } })} className="w-full bg-[#D4AF37] py-4 font-bold uppercase text-black flex justify-center gap-2"><Search size={20}/> Iniciar Varredura</button>
      </div>
    </div>
  );
};

const Results = () => {
  const { state } = useLocation();
  const [analysis, setAnalysis] = useState('Carregando análise IA...');
  useEffect(() => { 
    if (state?.searchParams) analyzeProfileRisk(state.searchParams).then(setAnalysis); 
  }, [state]);

  if (!state) return <div className="p-20 text-center">Acesso inválido.</div>;

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <h1 className="text-3xl font-bold mb-2">Relatório: <span className="text-[#D4AF37]">{state.searchParams.fullName}</span></h1>
      <div className="grid md:grid-cols-3 gap-6 mt-8">
        <div className="md:col-span-2 space-y-6">
          <div className="bg-[#121212] p-6 border border-white/10">
            <h3 className="font-bold text-lg mb-4 flex items-center gap-2"><Shield className="text-[#D4AF37]"/> Análise IA</h3>
            <p className="text-gray-300 text-sm whitespace-pre-line leading-relaxed">{analysis}</p>
          </div>
          <div className="bg-[#121212] p-6 border border-white/10">
            <h3 className="font-bold text-lg mb-4">Registros Públicos</h3>
            <div className="flex justify-between p-3 bg-black/40 mb-2 border border-white/5"><span>Antecedentes Criminais</span><span className="text-green-500 font-bold">Nada Consta</span></div>
            <div className="flex justify-between p-3 bg-black/40 border border-white/5"><span>Processos Cíveis</span><span className="text-green-500 font-bold">Nada Consta</span></div>
          </div>
        </div>
        <div className="space-y-6">
           <div className="bg-[#121212] p-6 border border-white/10 text-center">
             <div className="text-4xl font-bold text-green-500 mb-2">92/100</div>
             <div className="text-xs uppercase text-gray-500">Score de Transparência</div>
           </div>
        </div>
      </div>
    </div>
  );
};

const VerifiedList = () => (
  <div className="max-w-6xl mx-auto py-12 px-4">
    <h2 className="text-3xl font-serif font-bold text-center mb-10">Perfis Verificados</h2>
    <div className="grid md:grid-cols-3 gap-6">
      {MOCK_VERIFIED_PROFILES.map(p => (
        <div key={p.id} className="bg-[#121212] border border-white/10 rounded-sm overflow-hidden">
          <img src={p.imageUrl} className="w-full h-64 object-cover" />
          <div className="p-6">
            <h3 className="font-bold text-xl flex items-center gap-2">{p.name} <CheckCircle size={16} className="text-[#D4AF37]" /></h3>
            <p className="text-sm text-gray-400">{p.bio}</p>
          </div>
        </div>
      ))}
    </div>
  </div>
);

const Desabafo = () => {
  const { user, isMale, isAdmin } = useAuth();
  if (!isMale && !isAdmin) return <div className="p-20 text-center"><Lock className="mx-auto mb-4 text-[#D4AF37]"/>Área restrita para homens.</div>;

  const [posts, setPosts] = useState(MOCK_FORUM_POSTS);
  const [text, setText] = useState('');

  const addPost = () => {
    if (!text) return;
    setPosts([{ id: Date.now().toString(), author: user.name, content: text, likes: 0, timestamp: 'Agora', topic: 'Geral', replies: [] }, ...posts]);
    setText('');
  };

  return (
    <div className="max-w-3xl mx-auto py-12 px-4">
      <h1 className="text-3xl font-serif font-bold text-center mb-8 flex items-center justify-center gap-2"><MessageSquare className="text-[#D4AF37]" /> Fórum Desabafo</h1>
      <div className="bg-[#121212] p-6 mb-8 border border-white/10">
        <textarea className="w-full bg-black/50 border border-white/20 p-4 text-white rounded mb-4" placeholder="Compartilhe sua experiência..." value={text} onChange={e => setText(e.target.value)} />
        <button onClick={addPost} className="bg-[#D4AF37] text-black px-6 py-2 font-bold uppercase rounded-sm flex items-center gap-2"><Send size={16}/> Publicar</button>
      </div>
      <div className="space-y-4">
        {posts.map(post => (
          <div key={post.id} className="bg-[#121212] p-6 border border-white/5 rounded-sm">
            <div className="flex justify-between mb-2">
               <span className="font-bold text-sm text-gray-300">{post.author}</span>
               <span className="text-xs text-gray-600">{post.timestamp}</span>
            </div>
            <p className="text-gray-300 mb-4">{post.content}</p>
            <div className="flex gap-4 text-xs text-gray-500">
               <span className="flex items-center gap-1"><ThumbsUp size={14}/> {post.likes}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const AreYouOkay = () => {
  const { isMale, isAdmin } = useAuth();
  const { supportResources, sponsors } = useData();
  const [msg, setMsg] = useState('');
  const [advice, setAdvice] = useState('');

  if (!isMale && !isAdmin) return <div className="p-20 text-center"><Lock className="mx-auto mb-4 text-[#D4AF37]"/>Área restrita.</div>;

  const handleAdvice = async () => {
    setAdvice('Pensando...');
    const res = await getSupportiveAdvice(msg);
    setAdvice(res);
  };

  return (
    <div className="max-w-5xl mx-auto py-12 px-4">
      <h1 className="text-3xl font-serif font-bold text-center mb-10">Rede de Apoio</h1>
      <div className="grid md:grid-cols-2 gap-10">
        <div>
          <div className="bg-[#121212] p-8 border border-[#D4AF37]/30 rounded-sm mb-6">
            <h3 className="font-bold text-xl mb-4 text-white flex items-center gap-2"><User className="text-[#D4AF37]"/> Mentor IA</h3>
            <textarea className="w-full bg-black/50 border border-white/20 p-4 text-white rounded mb-4 h-32" placeholder="O que está pesando na sua mente?" value={msg} onChange={e => setMsg(e.target.value)} />
            <button onClick={handleAdvice} className="w-full bg-[#D4AF37] text-black font-bold uppercase py-3 rounded-sm">Pedir Conselho</button>
